function gcd(a, b) {
    a = Math.abs(a);
    b = Math.abs(b);
    while (b !== 0) {
        [a, b] = [b, a % b];
    }
    return a;
}

function normalize(v) {
    let [dx, dy] = v;
    if (dx === 0 && dy === 0) {
        return [0, 0];
    } else if (dx === 0) {
        return dy > 0 ? [0, 1] : [0, -1];
    } else if (dy === 0) {
        return dx > 0 ? [1, 0] : [-1, 0];
    } else {
        let g = gcd(dx, dy);
        dx = dx / g;
        dy = dy / g;
        if (dx < 0) {
            dx = -dx;
            dy = -dy;
        }
        return [dx, dy];
    }
}

function solve(points) {
    const n = points.length;
    let total_parallelograms = 0;
    const midMap = new Map();
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            const mid_x = x1 + x2;
            const mid_y = y1 + y2;
            const key = `${mid_x},${mid_y}`;
            midMap.set(key, (midMap.get(key) || 0) + 1);
        }
    }
    for (let count of midMap.values()) {
        total_parallelograms += Math.floor(count * (count - 1) / 2);
    }

    let slopeGroups = new Map();
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (i === j) continue;
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            const dx = x2 - x1;
            const dy = y2 - y1;
            const [ndx, ndy] = normalize([dx, dy]);
            const slopeKey = `${ndx},${ndy}`;
            let intercept;
            if (ndx === 0) {
                intercept = x1;
            } else {
                intercept = ndy * x1 - ndx * y1;
            }
            const interceptKey = `${intercept}`;

            if (!slopeGroups.has(slopeKey)) {
                slopeGroups.set(slopeKey, new Map());
            }
            const group = slopeGroups.get(slopeKey);
            group.set(interceptKey, (group.get(interceptKey) || 0) + 1);
        }
    }

    let F = 0;
    for (let group of slopeGroups.values()) {
        let total = 0;
        let sum_sq = 0;
        for (let count of group.values()) {
            total += count;
            sum_sq += count * count;
        }
        const F_group = (total * total - sum_sq) / 2;
        F += F_group;
    }

    return F - total_parallelograms;
}
```

