function gcd(a, b) {
    a = Math.abs(a);
    b = Math.abs(b);
    if (a < b) [a, b] = [b, a];
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
}

function solve(points) {
    const n = points.length;
    const slopeMap = {};
    const midMap = {};

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            const dx = x2 - x1;
            const dy = y2 - y1;

            const key_mid = `${x1 + x2},${y1 + y2}`;
            midMap[key_mid] = (midMap[key_mid] || 0) + 1;

            if (dx === 0 && dy === 0) continue;

            let key_slope;
            if (dx === 0) {
                key_slope = 'inf';
            } else {
                let g = gcd(dx, dy);
                let ndx = dx / g;
                let ndy = dy / g;
                if (ndx < 0) {
                    ndx = -ndx;
                    ndy = -ndy;
                }
                key_slope = `${ndx},${ndy}`;
            }

            if (!slopeMap[key_slope]) {
                slopeMap[key_slope] = [];
            }
            slopeMap[key_slope].push([i, j]);
        }
    }

    let totalDisjoint = 0;
    for (const key in slopeMap) {
        const segments = slopeMap[key];
        const m = segments.length;
        if (m < 2) continue;

        const totalPairs = m * (m - 1) / 2;
        const count = {};
        for (const [a, b] of segments) {
            count[a] = (count[a] || 0) + 1;
            count[b] = (count[b] || 0) + 1;
        }

        let sharedPairs = 0;
        for (const x in count) {
            const c = count[x];
            sharedPairs += c * (c - 1) / 2;
        }

        totalDisjoint += (totalPairs - sharedPairs);
    }

    let P = 0;
    for (const key in midMap) {
        const t = midMap[key];
        if (t >= 2) {
            P += t * (t - 1) / 2;
        }
    }

    return totalDisjoint - P;
}
