function gcd(a, b) {
    a = Math.abs(a);
    b = Math.abs(b);
    if (b === 0) return a;
    return gcd(b, a % b);
}

function normalizeLine(a, b, c) {
    if (a === 0 && b === 0) {
        return [0, 0, 0];
    }
    let g = gcd(a, gcd(b, c));
    if (g === 0) {
        g = 1;
    }
    a = a / g;
    b = b / g;
    c = c / g;
    if (a < 0 || (a === 0 && b < 0)) {
        a = -a;
        b = -b;
        c = -c;
    }
    return [a, b, c];
}

function solve(points) {
    const n = points.length;
    const slopeMap = new Map();

    for (let i = 0; i < n; i++) {
        const [x0, y0] = points[i];
        for (let j = i+1; j < n; j++) {
            const [x1, y1] = points[j];
            let dx = x1 - x0;
            let dy = y1 - y0;
            if (dx === 0 && dy === 0) {
                continue;
            }
            let gSlope = gcd(dx, dy);
            if (gSlope !== 0) {
                dx = Math.floor(dx / gSlope);
                dy = Math.floor(dy / gSlope);
            }
            if (dx < 0 || (dx === 0 && dy < 0)) {
                dx = -dx;
                dy = -dy;
            }
            const slopeKey = `${dx},${dy}`;

            const a = dy;
            const b = -dx;
            const c = -a * x0 - b * y0;
            const lineKey = normalizeLine(a, b, c).join(',');

            if (!slopeMap.has(slopeKey)) {
                slopeMap.set(slopeKey, new Map());
            }
            const linesMap = slopeMap.get(slopeKey);
            if (!linesMap.has(lineKey)) {
                linesMap.set(lineKey, new Set());
            }
            const pointSet = linesMap.get(lineKey);
            pointSet.add(JSON.stringify([x0, y0]));
            pointSet.add(JSON.stringify([x1, y1]));
        }
    }

    let total = 0;
    for (const linesMap of slopeMap.values()) {
        const aList = [];
        for (const pointSet of linesMap.values()) {
            const m = pointSet.size;
            if (m < 2) continue;
            aList.push(m * (m - 1) / 2);
        }
        if (aList.length === 0) continue;
        const S = aList.reduce((acc, val) => acc + val, 0);
        const Q = aList.reduce((acc, val) => acc + val * val, 0);
        const groupCount = (S * S - Q) / 2;
        total += groupCount;
    }

    return total;
}
